class Solution:
    def generateTag(self, caption):
        words = caption.split()
        parts = []
        for idx, w in enumerate(words):
            w = w.lower()
            if idx == 0:
                parts.append(w)
            else:
                parts.append(w[0].upper() + w[1:])
        tag = '#' + ''.join(parts)
        return tag[:100]

