var generateTag = function(caption) {
    const ws = caption.split(/\s+/).filter(x => x.length > 0);
    let res = '#';
    for (let i = 0; i < ws.length; i++) {
        const w = ws[i].toLowerCase();
        res += (i === 0) ? w : w.charAt(0).toUpperCase() + w.slice(1);
    }
    return res.slice(0, 100);
};
